'use client'

import Link from 'next/link'
import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { User } from '@supabase/supabase-js'
import { Navbar } from '@/components/Navbar'
import { Footer } from '@/components/Footer'
import { PostCard } from '@/components/PostCard'
import { QuestionCard } from '@/components/QuestionCard'
import { Post } from '@/types'
import { ChevronDown } from 'lucide-react'

type SortOption = 'new' | 'hot' | 'top-week' | 'top-month' | 'top-all'
type FeedTab = 'all' | 'following'

export default function FeedPage() {
  const [user, setUser] = useState<User | null>(null)
  const [posts, setPosts] = useState<Post[]>([])
  const [loading, setLoading] = useState(true)
  const [selectedTag, setSelectedTag] = useState<string | null>(null)
  const [filter, setFilter] = useState<'all' | 'article' | 'question'>('all')
  const [sortBy, setSortBy] = useState<SortOption>('new')
  const [feedTab, setFeedTab] = useState<FeedTab>('all')
  const [followingIds, setFollowingIds] = useState<string[]>([])
  const supabase = createClient()

  const [officialTags, setOfficialTags] = useState<string[]>([])

  useEffect(() => {
    // Get user and their following list
    const initUser = async () => {
      const { data: { user } } = await supabase.auth.getUser()
      setUser(user)

      if (user) {
        // Get list of users this user follows
        const { data: follows } = await supabase
          .from('follows')
          .select('following_id')
          .eq('follower_id', user.id)

        if (follows) {
          setFollowingIds(follows.map(f => f.following_id))
        }
      }
    }
    initUser()

    // Fetch official tags
    const loadTags = async () => {
      const { data } = await supabase.from('tags').select('label').order('label')
      if (data) {
        setOfficialTags(data.map(t => t.label))
      }
    }
    loadTags()
  }, [supabase])

  // Fetch posts when filters change
  useEffect(() => {
    const loadPosts = async () => {
      setLoading(true)
      try {
        let query = supabase
          .from('posts')
          .select(`
            *,
            author:users!posts_author_id_fkey(id, name, email)
          `)
          .eq('status', 'published')

        // Content type filter
        if (filter !== 'all') {
          query = query.eq('content_type', filter)
        }

        // Following filter
        if (feedTab === 'following' && followingIds.length > 0) {
          query = query.in('author_id', followingIds)
        }

        // Sort by
        if (sortBy === 'new') {
          query = query.order('created_at', { ascending: false })
        } else if (sortBy === 'hot') {
          // Hot sort: recent + high votes (simplified - just recent with votes)
          query = query.order('vote_count', { ascending: false, nullsFirst: false })
            .order('created_at', { ascending: false })
        } else if (sortBy.startsWith('top-')) {
          // Top sort by timeframe
          const now = new Date()
          let since: Date

          if (sortBy === 'top-week') {
            since = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000)
          } else if (sortBy === 'top-month') {
            since = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000)
          } else {
            since = new Date(0) // All time
          }

          query = query
            .gte('created_at', since.toISOString())
            .order('vote_count', { ascending: false, nullsFirst: false })
        }

        const { data, error } = await query.limit(50)

        if (error) {
          console.error('Error fetching posts:', error)
        } else {
          setPosts(data || [])
        }
      } catch (error) {
        console.error('Error:', error)
      } finally {
        setLoading(false)
      }
    }

    loadPosts()
  }, [supabase, filter, sortBy, feedTab, followingIds])

  const filteredPosts = selectedTag
    ? posts.filter(post => post.tags?.includes(selectedTag))
    : posts

  const SORT_OPTIONS: { value: SortOption; label: string }[] = [
    { value: 'new', label: 'New' },
    { value: 'hot', label: 'Hot' },
    { value: 'top-week', label: 'Top (Week)' },
    { value: 'top-month', label: 'Top (Month)' },
    { value: 'top-all', label: 'Top (All)' },
  ]

  return (
    <div className="min-h-screen bg-background dark:bg-dark-bg flex flex-col">
      <Navbar user={user} />

      <main className="flex-1 container-custom max-w-7xl py-8">
        <div className="flex flex-col lg:flex-row gap-8">
          {/* Sidebar - Tags */}
          <aside className="lg:w-64 flex-shrink-0">
            <div className="card p-4">
              <h2 className="text-lg font-semibold text-primary dark:text-dark-text mb-4">Tags</h2>
              <div className="space-y-2">
                <button
                  onClick={() => setSelectedTag(null)}
                  className={`w-full text-left px-3 py-2 rounded-lg transition-colors ${selectedTag === null
                    ? 'bg-primary/10 text-primary dark:bg-primary-light/20 dark:text-primary-light'
                    : 'text-text dark:text-dark-text hover:bg-gray-100 dark:hover:bg-dark-border'
                    }`}
                >
                  All Posts
                </button>
                {officialTags.map(tag => (
                  <button
                    key={tag}
                    onClick={() => setSelectedTag(tag)}
                    className={`w-full text-left px-3 py-2 rounded-lg transition-colors ${selectedTag === tag
                      ? 'bg-primary/10 text-primary dark:bg-primary-light/20 dark:text-primary-light'
                      : 'text-text dark:text-dark-text hover:bg-gray-100 dark:hover:bg-dark-border'
                      }`}
                  >
                    {tag}
                  </button>
                ))}
              </div>
            </div>
          </aside>

          {/* Main Content - Posts */}
          <div className="flex-1">
            {/* Feed Tabs + Sort */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
              {/* All / Following Tabs */}
              {user && (
                <div className="flex border-b border-gray-200 dark:border-dark-border">
                  <button
                    onClick={() => setFeedTab('all')}
                    className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${feedTab === 'all'
                        ? 'border-primary text-primary dark:border-accent-light dark:text-accent-light'
                        : 'border-transparent text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text'
                      }`}
                  >
                    All
                  </button>
                  <button
                    onClick={() => setFeedTab('following')}
                    className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${feedTab === 'following'
                        ? 'border-primary text-primary dark:border-accent-light dark:text-accent-light'
                        : 'border-transparent text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text'
                      }`}
                  >
                    Following
                    {followingIds.length > 0 && (
                      <span className="ml-1.5 text-xs text-text-light dark:text-dark-text-muted">
                        ({followingIds.length})
                      </span>
                    )}
                  </button>
                </div>
              )}

              {/* Sort + Filter */}
              <div className="flex items-center gap-3">
                {/* Sort Dropdown */}
                <div className="relative">
                  <select
                    value={sortBy}
                    onChange={(e) => setSortBy(e.target.value as SortOption)}
                    className="appearance-none pl-3 pr-8 py-1.5 text-sm rounded-md border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-surface text-text dark:text-dark-text cursor-pointer"
                  >
                    {SORT_OPTIONS.map(opt => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                  <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-4 h-4 text-text-light pointer-events-none" />
                </div>

                {/* Type Filter */}
                <div className="flex bg-gray-100 dark:bg-dark-surface rounded-lg p-1">
                  {(['all', 'article', 'question'] as const).map((type) => (
                    <button
                      key={type}
                      onClick={() => setFilter(type)}
                      className={`px-3 py-1 rounded-md text-sm font-medium transition-all ${filter === type
                        ? 'bg-white dark:bg-dark-bg text-primary shadow-sm'
                        : 'text-text-light dark:text-dark-text-muted hover:text-text dark:hover:text-dark-text'
                        }`}
                    >
                      {type.charAt(0).toUpperCase() + type.slice(1)}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Posts */}
            {loading ? (
              <div className="card p-8 text-center">
                <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-primary dark:border-accent-light"></div>
                <p className="mt-4 text-text-light dark:text-dark-text-muted">Loading posts...</p>
              </div>
            ) : filteredPosts.length === 0 ? (
              <div className="card p-8 text-center">
                <p className="text-text-light dark:text-dark-text-muted">
                  {feedTab === 'following' && followingIds.length === 0
                    ? 'Follow researchers to see their posts here.'
                    : selectedTag
                      ? `No posts found with tag "${selectedTag}"`
                      : 'No posts yet. Be the first to create one!'}
                </p>
                {user && (
                  <Link
                    href="/editor"
                    className="inline-block mt-4 btn btn-primary"
                  >
                    Create Post
                  </Link>
                )}
              </div>
            ) : (
              <div className="space-y-6">
                {filteredPosts.map(post => (
                  post.content_type === 'question' ? (
                    <QuestionCard key={post.id} post={post} />
                  ) : (
                    <PostCard key={post.id} post={post} />
                  )
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      <Footer />
    </div>
  )
}
